-- Enhanced Texas Freelance Service Agreement v2
-- Improvements:
-- - Texas Business & Commerce Code references
-- - Texas Deceptive Trade Practices Act (DTPA) acknowledgment
-- - Prompt payment clause (Texas prompt payment laws - Gov't Code Ch 2251, Bus & Com Code Ch 35)
-- - Strengthened independent contractor classification (TX TWC guidelines)
-- - Texas choice of law with venue in appropriate county
-- - Mechanic's lien waiver clause (TX Property Code Ch 53)
-- - Non-solicitation clause (enforceable in TX unlike non-competes)
-- - Professional liability/E&O insurance requirements
-- - Enhanced confidentiality with Texas Uniform Trade Secrets Act (TUTSA) references

INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'freelance_service',
  'us_texas',
  2,
  'Freelance Services Agreement (Texas)',
  'This Freelance Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}} ("Client"), a {{party_a_entity_type}} organized under the laws of {{party_a_state}}, with its principal place of business at {{party_a_address}}, and {{party_b_name}} doing business as {{party_b_company}} ("Freelancer"), with a principal place of business at {{party_b_address}}. Client and Freelancer may be referred to herein individually as a "Party" and collectively as the "Parties."',
  'WHEREAS, Client desires to engage Freelancer to provide certain professional freelance services for the project known as {{project_name}};
WHEREAS, Freelancer represents that Freelancer possesses the skills, qualifications, and experience necessary to perform such services;
WHEREAS, the Parties intend that Freelancer shall perform the services as an independent contractor and not as an employee of Client;
NOW, THEREFORE, in consideration of the mutual covenants and promises herein contained, and for other good and valuable consideration, the receipt and sufficiency of which are hereby acknowledged, the Parties agree as follows:',
  '[{"id":"definitions","title":"1. DEFINITIONS","content":"1.1 \"Deliverables\" means the work product, items, materials, and other outputs to be provided by Freelancer as described in Section 2 and/or as otherwise agreed in writing by the Parties.\n\n1.2 \"Services\" means the professional services described in Section 2 and any additional services expressly agreed in a written change order or statement of work signed by both Parties.\n\n1.3 \"Confidential Information\" has the meaning set forth in Section 10.\n\n1.4 \"Client Materials\" means any materials, content, data, software, documentation, trademarks, trade secrets, or other information provided by or on behalf of Client to Freelancer in connection with this Agreement.\n\n1.5 \"Freelancer Materials\" means any tools, templates, pre-existing works, libraries, know-how, methodologies, processes, software, and other materials owned or controlled by Freelancer prior to the Effective Date or developed by Freelancer outside the scope of this Agreement without use of Client Confidential Information.\n\n1.6 \"Work Product\" means all Deliverables and other work product created by Freelancer in the performance of the Services, excluding Freelancer Materials.\n\n1.7 \"Business Day\" means any day other than a Saturday, Sunday, or legal holiday in the State of Texas.\n\n1.8 \"Force Majeure Event\" means any act of God, war, terrorism, riot, natural disaster, pandemic, government action, or other event beyond a Party''s reasonable control.","type":"standard","order":1},{"id":"services_scope","title":"2. SERVICES; PROJECT SCOPE","content":"2.1 Engagement. Client hereby engages Freelancer, and Freelancer accepts such engagement, to perform the Services for the project known as {{project_name}}.\n\n2.2 Scope of Services. Freelancer shall perform the following Services: {{services_description}}.\n\n2.3 Deliverables. Freelancer shall provide the following Deliverables: {{deliverables}}.\n\n2.4 Standard of Performance. Freelancer shall perform the Services in a professional, workmanlike manner consistent with industry standards applicable to such services in the State of Texas.\n\n2.5 Out-of-Scope Items. Any tasks, services, or deliverables not expressly included in Sections 2.2 and 2.3 are excluded from this Agreement. If Client requests out-of-scope work, the Parties shall follow the change order process in Section 4.\n\n2.6 Client Cooperation. Client shall provide Freelancer with timely access to Client Materials, information, personnel, decisions, and approvals reasonably necessary for Freelancer to perform the Services. Freelancer shall not be responsible for delays caused by Client''s failure to cooperate in a timely manner.\n\n2.7 Compliance. Each Party shall perform its obligations under this Agreement in compliance with all applicable federal, state, and local laws, rules, and regulations, including applicable Texas laws.","type":"standard","order":2},{"id":"timeline_milestones","title":"3. TIMELINE; MILESTONES","content":"3.1 Project Schedule. The Parties shall mutually agree in writing on any project schedule, milestones, or deadlines (a \"Project Schedule\"). Unless otherwise agreed, the initial Project Schedule is as follows: {{project_timeline}}.\n\n3.2 Dependencies. Any Project Schedule is contingent upon Client''s timely provision of required inputs, feedback, approvals, and Client Materials. Freelancer shall not be responsible for missed deadlines caused by Client delays, scope changes, or Force Majeure Events.\n\n3.3 Delivery. Freelancer shall deliver Deliverables in the format(s) and via the method(s) agreed by the Parties. Unless otherwise specified, delivery shall be by electronic transmission.\n\n3.4 Review and Acceptance. Client shall have {{review_period}} Business Days (or 10 Business Days if not specified) to review each Deliverable after receipt. Unless Client provides written notice of material non-conformity within such period, the Deliverable shall be deemed accepted. If Client timely rejects a Deliverable, Freelancer shall use commercially reasonable efforts to correct the non-conformity.\n\n3.5 No Guaranteed Results. Freelancer will perform the Services professionally but does not guarantee any particular business, financial, marketing, or other outcome from the Services or Deliverables.","type":"standard","order":3},{"id":"changes","title":"4. CHANGES; CHANGE ORDERS","content":"4.1 Change Requests. Either Party may request changes to the Services, Deliverables, Project Schedule, or other terms of this Agreement.\n\n4.2 Change Order Required. Any material change must be documented in a written change order describing the revised scope, Deliverables, timeline, and any fee adjustment. Freelancer is not obligated to perform changed work until the change order is signed or confirmed in writing by both Parties.\n\n4.3 Effect on Fees and Timeline. Changes may require adjustments to fees, delivery dates, or other terms. Client acknowledges that requesting changes may extend timelines and increase costs.\n\n4.4 Verbal Instructions. Any verbal instructions from Client shall not be binding unless confirmed in writing within five (5) Business Days.","type":"standard","order":4},{"id":"payment_texas_prompt","title":"5. FEES; INVOICING; TEXAS PROMPT PAYMENT","content":"5.1 Fees. In consideration for the Services, Client shall pay Freelancer the following fees: (a) a project fee of {{payment_amount}}; and/or (b) {{hourly_rate}} per hour for time-and-materials work, as specified in Section 2 or applicable change orders.\n\n5.2 Deposit. If applicable, Client shall pay a non-refundable deposit of {{deposit_amount}} upon execution of this Agreement. The deposit shall be credited against the total fees due.\n\n5.3 Invoicing. Freelancer shall invoice Client as follows: {{invoice_schedule}}. If not otherwise specified, Freelancer shall invoice upon completion of each milestone or Deliverable, or monthly for ongoing services.\n\n5.4 Payment Terms; Texas Prompt Payment. Client shall pay all undisputed invoice amounts within {{payment_terms}} days of receipt of invoice (or 30 days if not specified). THE PARTIES ACKNOWLEDGE AND AGREE THAT TIMELY PAYMENT IS OF THE ESSENCE. Pursuant to Texas Business and Commerce Code Chapter 35, overdue payments shall accrue interest at the rate of one and one-half percent (1.5%) per month, or eighteen percent (18%) per annum, or the maximum rate permitted under Texas law, whichever is less, from the due date until paid in full.\n\n5.5 Disputed Amounts. Client shall notify Freelancer in writing within ten (10) Business Days of receipt of an invoice of any good-faith dispute, describing the basis for the dispute in reasonable detail. Client shall timely pay all undisputed portions. The Parties shall work in good faith to resolve any dispute promptly.\n\n5.6 Suspension of Services. If any undisputed invoice remains unpaid for more than fifteen (15) days past due, Freelancer may, upon five (5) Business Days'' written notice, suspend performance of the Services until payment is received, without liability to Client.\n\n5.7 Collection Costs. If Freelancer must take legal action to collect amounts due under this Agreement, Client shall pay all reasonable costs of collection, including court costs and attorneys'' fees, to the extent permitted by Texas law.\n\n5.8 Taxes. Freelancer is solely responsible for all federal, state, and local taxes arising from fees received under this Agreement, including self-employment taxes. Texas does not impose a state income tax on individuals. Client shall not withhold any taxes from payments to Freelancer. If any sales tax applies to the Services, Client shall be responsible for such sales tax unless Freelancer is required to collect it.\n\n5.9 No Contingent Fees. Fees are not contingent on results unless expressly agreed in a separate written agreement.","type":"standard","order":5},{"id":"revisions","title":"6. REVISIONS; CLIENT FEEDBACK","content":"6.1 Included Revisions. Unless the Parties expressly agree in writing to a specific number of revision rounds, {{revision_rounds}} rounds of reasonable revisions consistent with the agreed scope are included (or two rounds if not specified).\n\n6.2 Revision Limits. Revisions do not include: (a) changes in scope; (b) new concepts or directions not previously approved; (c) changes requested due to Client-provided errors or late changes; or (d) substantial rework due to Client delays. Such items constitute out-of-scope work and are subject to Section 4.\n\n6.3 Timely Feedback. Client shall provide consolidated feedback in a timely manner. Delayed or piecemeal feedback may impact the Project Schedule.\n\n6.4 Final Approval. Client''s approval of any Deliverable, or use of any Deliverable in commerce or production, shall constitute final acceptance of such Deliverable.","type":"standard","order":6},{"id":"expenses","title":"7. EXPENSES; THIRD-PARTY SERVICES","content":"7.1 Expenses. Unless expressly pre-approved in writing by Client, Freelancer shall bear all ordinary business expenses. Pre-approved, reasonable, and necessary out-of-pocket expenses incurred for the benefit of the project shall be reimbursed by Client upon receipt of itemized documentation.\n\n7.2 Third-Party Services. If the Services require third-party tools, hosting, licenses, subscriptions, stock assets, or materials, Client is responsible for obtaining and maintaining such third-party products and their associated costs unless otherwise agreed in writing.\n\n7.3 Subcontractors. Freelancer may engage subcontractors to assist with the Services, provided that Freelancer remains fully responsible for the work of such subcontractors and ensures they are bound by confidentiality obligations at least as protective as those in this Agreement.","type":"standard","order":7},{"id":"independent_contractor_texas","title":"8. INDEPENDENT CONTRACTOR STATUS; TEXAS WORKFORCE COMMISSION COMPLIANCE","content":"8.1 Independent Contractor. Freelancer is an independent contractor and not an employee, agent, joint venturer, or partner of Client. Freelancer has no authority to bind Client or represent that Freelancer is an employee or agent of Client.\n\n8.2 Control and Manner of Work. Freelancer retains sole and exclusive control over the manner, method, and means of performing the Services. Client''s right is limited to specifying desired results, project requirements, and deadlines. Freelancer is free to determine the time, place, and manner of performing the Services, subject to meeting agreed deadlines.\n\n8.3 Texas Workforce Commission Guidelines. The Parties intend that this Agreement satisfies the criteria for independent contractor status under Texas law and Texas Workforce Commission (TWC) guidelines. The Parties specifically agree that:\n  (a) Freelancer has a separately established business or occupation;\n  (b) Freelancer has the right to perform similar services for others during the term of this Agreement;\n  (c) Freelancer is free from control over the details of how the Services are performed;\n  (d) Freelancer provides their own equipment, tools, and materials;\n  (e) Freelancer bears the risk of profit or loss;\n  (f) Freelancer invoices Client for Services and is paid upon completion of work;\n  (g) Freelancer is not economically dependent on Client for the majority of their income.\n\n8.4 No Employee Benefits. Freelancer is not eligible for and waives any right to claim any benefits from Client, including workers'' compensation (except as required by law), unemployment insurance, health insurance, paid leave, retirement benefits, or any other employee benefits.\n\n8.5 Taxes and Withholding. Freelancer is solely responsible for all payroll taxes, self-employment taxes, income taxes, and other tax obligations arising from payments under this Agreement. Client shall issue IRS Form 1099-NEC to Freelancer as required by law.\n\n8.6 Equipment and Place of Work. Freelancer shall provide their own equipment, tools, software, and materials necessary to perform the Services. Freelancer may perform the Services at any location of Freelancer''s choosing, unless the Parties agree otherwise for specific tasks.\n\n8.7 Non-Exclusivity. Freelancer may perform services for other clients during the term of this Agreement, provided such work does not create a conflict of interest or breach confidentiality obligations.\n\n8.8 Indemnification for Misclassification. Each Party agrees to indemnify and hold harmless the other Party from any claims, damages, penalties, or liabilities arising from any governmental determination that the classification of Freelancer under this Agreement is incorrect.","type":"standard","order":8},{"id":"ip_ownership","title":"9. INTELLECTUAL PROPERTY; OWNERSHIP; LICENSES","content":"9.1 Client Ownership of Work Product. Subject to Section 9.2 and Freelancer''s receipt of all amounts due under this Agreement, Freelancer hereby irrevocably assigns to Client all right, title, and interest in and to the Work Product, including all copyrights, patents, trade secrets, and other intellectual property rights therein.\n\n9.2 Condition Precedent. Notwithstanding Section 9.1, title to Work Product shall not transfer to Client until Freelancer has received full payment for all amounts due under this Agreement. Until such time, Freelancer retains all rights in the Work Product.\n\n9.3 Freelancer Materials. Freelancer retains all right, title, and interest in and to Freelancer Materials. To the extent any Freelancer Materials are incorporated into the Deliverables, Freelancer grants Client a non-exclusive, worldwide, perpetual, royalty-free, fully paid-up license to use, reproduce, display, perform, distribute, and create derivative works of such Freelancer Materials solely as embedded in or necessary to use the Deliverables, subject to full payment.\n\n9.4 Client Materials. Client retains all right, title, and interest in and to Client Materials. Client grants Freelancer a limited, non-exclusive, non-transferable license to use Client Materials solely to perform the Services during the term of this Agreement.\n\n9.5 Work Made for Hire. To the extent any Work Product qualifies as a \"work made for hire\" under 17 U.S.C. § 101, it shall be deemed a work made for hire for Client. To the extent any Work Product does not so qualify, Freelancer hereby assigns it to Client as provided in Section 9.1.\n\n9.6 Further Assurances. Freelancer shall execute and deliver such documents (including copyright assignments and patent applications) and take such actions as Client may reasonably request to evidence, perfect, maintain, or enforce Client''s rights in the Work Product.\n\n9.7 Moral Rights Waiver. To the maximum extent permitted under applicable law, including Texas and federal law, Freelancer waives and agrees not to assert any \"moral rights\" or similar rights (including rights of attribution and integrity) in the Work Product against Client or its successors and assigns.\n\n9.8 Portfolio Use. Unless Client objects in writing, Freelancer may include non-confidential excerpts or images of the Deliverables in Freelancer''s portfolio solely to demonstrate Freelancer''s work, provided that such use does not disclose Client Confidential Information and complies with any brand guidelines provided by Client.","type":"negotiable","order":9},{"id":"confidentiality_tutsa","title":"10. CONFIDENTIALITY; TEXAS UNIFORM TRADE SECRETS ACT","content":"10.1 Confidential Information. \"Confidential Information\" means any non-public information disclosed by or on behalf of a Party (the \"Disclosing Party\") to the other Party (the \"Receiving Party\"), whether oral, written, electronic, visual, or otherwise, that is designated as confidential or that reasonably should be understood to be confidential given the nature of the information and the circumstances of disclosure. Confidential Information includes, without limitation: business plans, customer lists, customer information, pricing, financial information, product information, source code, designs, marketing strategies, technical data, know-how, trade secrets, and the terms of this Agreement.\n\n10.2 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate by competent evidence: (a) is or becomes publicly available through no breach of this Agreement; (b) was lawfully in the Receiving Party''s possession before disclosure without any obligation of confidentiality; (c) is lawfully received from a third party without restriction and without breach of any obligation; or (d) is independently developed by the Receiving Party without use of or reference to the Disclosing Party''s Confidential Information.\n\n10.3 Use and Nondisclosure. The Receiving Party shall: (a) use Confidential Information solely to perform or receive the Services and to exercise rights under this Agreement; (b) not disclose Confidential Information to any third party except as permitted herein; and (c) protect Confidential Information using at least the same degree of care it uses to protect its own confidential information, but no less than reasonable care.\n\n10.4 Permitted Disclosures. The Receiving Party may disclose Confidential Information to its employees, contractors, and professional advisors who have a need to know and who are bound by confidentiality obligations at least as protective as those in this Agreement. The Receiving Party remains responsible for any breach by such persons.\n\n10.5 Compelled Disclosure. If the Receiving Party is required by law, regulation, subpoena, or court order to disclose Confidential Information, it shall (to the extent legally permitted) provide prompt written notice to the Disclosing Party to allow the Disclosing Party to seek a protective order. The Receiving Party shall cooperate with such efforts and shall disclose only the minimum information required.\n\n10.6 Texas Uniform Trade Secrets Act. The Parties acknowledge that Confidential Information may include trade secrets as defined under the Texas Uniform Trade Secrets Act (Texas Civil Practice and Remedies Code, Chapter 134A). Unauthorized use or disclosure of trade secrets may result in injunctive relief and damages, including exemplary damages for willful and malicious misappropriation.\n\n10.7 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. § 1833(b), an individual shall not be held criminally or civilly liable under any federal or state trade secret law for the disclosure of a trade secret made: (i) in confidence to a federal, state, or local government official, or to an attorney, solely for the purpose of reporting or investigating a suspected violation of law; or (ii) in a complaint or other document filed in a lawsuit or other proceeding, if such filing is made under seal.\n\n10.8 Return or Destruction. Upon termination of this Agreement or upon the Disclosing Party''s request, the Receiving Party shall promptly return or destroy (at the Disclosing Party''s option) all Confidential Information in its possession, except that the Receiving Party may retain copies as required by law or for legitimate archival purposes, subject to continuing confidentiality obligations.\n\n10.9 Duration. Confidentiality obligations under this Section 10 shall survive termination of this Agreement for {{confidentiality_period}} years (or five years if not specified), except that obligations with respect to trade secrets shall continue for as long as such information remains a trade secret under applicable law.","type":"standard","order":10},{"id":"non_solicitation","title":"11. NON-SOLICITATION","content":"11.1 Non-Solicitation of Employees. During the term of this Agreement and for {{non_solicitation_period}} months thereafter (or twelve months if not specified), Freelancer shall not, directly or indirectly, solicit, recruit, or hire, or attempt to solicit, recruit, or hire, any employee or contractor of Client with whom Freelancer had material contact in connection with this Agreement, without Client''s prior written consent.\n\n11.2 Non-Solicitation of Clients (If Applicable). If Freelancer is provided access to Client''s customer or client lists or relationships in connection with the Services, Freelancer shall not, during the term of this Agreement and for {{non_solicitation_period}} months thereafter (or twelve months if not specified), directly solicit any such customers or clients for services that compete with Client''s business.\n\n11.3 Reasonableness. The Parties acknowledge that the restrictions in this Section 11 are reasonable and necessary to protect Client''s legitimate business interests, and that such restrictions are enforceable under Texas law. If any court of competent jurisdiction determines that any restriction is overbroad or unenforceable, the Parties agree that such court may modify such restriction to make it reasonable and enforceable.\n\n11.4 Acknowledgment Regarding Non-Competes. The Parties acknowledge that, under Texas Business and Commerce Code Section 15.50, covenants not to compete must meet specific requirements to be enforceable. This Agreement does not contain a general non-compete provision, and Freelancer remains free to engage in any lawful profession, trade, or business, subject to the limited non-solicitation provisions above and confidentiality obligations.","type":"negotiable","order":11},{"id":"warranties","title":"12. REPRESENTATIONS AND WARRANTIES","content":"12.1 Freelancer Representations and Warranties. Freelancer represents and warrants that:\n  (a) Freelancer has the full right, power, and authority to enter into this Agreement and to perform all of Freelancer''s obligations hereunder;\n  (b) The Services will be performed in a professional, workmanlike manner consistent with industry standards;\n  (c) The Deliverables will be original works created by Freelancer (or properly licensed) and will not infringe or misappropriate any third party''s intellectual property rights, privacy rights, or other rights;\n  (d) Freelancer has and will maintain all necessary licenses, permits, and qualifications required to perform the Services;\n  (e) To Freelancer''s knowledge, the Deliverables will not contain any virus, malware, or other harmful code;\n  (f) Freelancer will comply with all applicable laws in performing the Services.\n\n12.2 Client Representations and Warranties. Client represents and warrants that:\n  (a) Client has the full right, power, and authority to enter into this Agreement;\n  (b) Client has the right to provide Client Materials to Freelancer;\n  (c) Client Materials and Client''s instructions will not infringe or misappropriate any third party''s intellectual property rights;\n  (d) Client will use the Deliverables in compliance with applicable laws.\n\n12.3 Disclaimer. EXCEPT AS EXPRESSLY STATED IN THIS AGREEMENT, NEITHER PARTY MAKES ANY OTHER WARRANTIES, WHETHER EXPRESS, IMPLIED, STATUTORY, OR OTHERWISE. EACH PARTY DISCLAIMS ALL IMPLIED WARRANTIES, INCLUDING ANY IMPLIED WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, AND NON-INFRINGEMENT, TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW.","type":"standard","order":12},{"id":"dtpa_acknowledgment","title":"13. TEXAS DECEPTIVE TRADE PRACTICES ACT ACKNOWLEDGMENT","content":"13.1 DTPA Waiver. CLIENT ACKNOWLEDGES THAT CLIENT IS A BUSINESS CONSUMER AS DEFINED BY THE TEXAS DECEPTIVE TRADE PRACTICES-CONSUMER PROTECTION ACT (TEXAS BUSINESS AND COMMERCE CODE, CHAPTER 17) (\"DTPA\"). TO THE EXTENT PERMITTED BY LAW, CLIENT HEREBY WAIVES ITS RIGHTS UNDER THE DTPA, OTHER THAN SECTION 17.555, WHICH RELATES TO A CAUSE OF ACTION FOR BODILY INJURY OR DEATH OR FOR GROSS NEGLIGENCE.\n\n13.2 Written Notice. CLIENT REPRESENTS THAT CLIENT HAS BEEN REPRESENTED BY LEGAL COUNSEL IN CONNECTION WITH THIS TRANSACTION OR HAS HAD AT LEAST THREE (3) BUSINESS DAYS TO REVIEW THIS WAIVER AND HAS NOT BEEN INDUCED TO ENTER INTO THIS AGREEMENT BY ANY REPRESENTATION OR WARRANTY NOT EXPRESSLY SET FORTH IN THIS AGREEMENT.\n\n13.3 Separate Consideration. CLIENT ACKNOWLEDGES THAT THIS DTPA WAIVER WAS BARGAINED FOR, THAT IT IS A MATERIAL PART OF THIS AGREEMENT, AND THAT THE TOTAL CONSIDERATION FOR THIS AGREEMENT REFLECTS THE EXISTENCE OF THIS WAIVER.\n\n13.4 Voluntary Agreement. THIS WAIVER IS MADE VOLUNTARILY AND IS NOT UNCONSCIONABLE. THE PARTIES HAVE APPROXIMATELY EQUAL BARGAINING POWER IN THIS TRANSACTION.\n\n13.5 Freelancer Acknowledgment. Freelancer also acknowledges the applicability of this DTPA waiver and agrees that, to the extent permitted by law, Freelancer waives any rights under the DTPA with respect to this Agreement.","type":"standard","order":13},{"id":"insurance","title":"14. INSURANCE; PROFESSIONAL LIABILITY","content":"14.1 Freelancer Insurance. During the term of this Agreement, Freelancer shall maintain the following insurance coverage:\n  (a) General Liability Insurance with minimum coverage of {{liability_coverage}} (or $1,000,000 per occurrence if not specified);\n  (b) Professional Liability / Errors & Omissions Insurance with minimum coverage of {{eo_coverage}} (or $1,000,000 per claim if not specified), covering claims arising from Freelancer''s professional services;\n  (c) If Freelancer uses employees or subcontractors, Workers'' Compensation Insurance as required by Texas law.\n\n14.2 Certificate of Insurance. Upon Client''s written request, Freelancer shall provide a certificate of insurance evidencing such coverage.\n\n14.3 Self-Insurance. If Freelancer does not maintain professional liability insurance, Freelancer shall disclose this to Client in writing, and Client may require Freelancer to obtain such insurance or may proceed at Client''s own risk.\n\n14.4 No Limitation of Liability. The insurance requirements in this Section do not limit Freelancer''s liability under this Agreement.","type":"optional","order":14},{"id":"indemnification","title":"15. INDEMNIFICATION","content":"15.1 Indemnification by Freelancer. Freelancer shall indemnify, defend, and hold harmless Client and its officers, directors, employees, agents, successors, and assigns from and against any and all third-party claims, demands, losses, damages, liabilities, costs, and expenses (including reasonable attorneys'' fees and court costs) arising out of or relating to:\n  (a) Freelancer''s breach of any representation, warranty, or obligation under this Agreement;\n  (b) Any claim that the Deliverables (as delivered and used as contemplated by this Agreement) infringe or misappropriate any third party''s intellectual property rights;\n  (c) Freelancer''s gross negligence or willful misconduct;\n  (d) Any claim by any governmental authority regarding Freelancer''s tax obligations or worker classification;\n\nprovided that Client (i) promptly notifies Freelancer in writing of such claim, (ii) gives Freelancer sole control of the defense and settlement (subject to Section 15.4), and (iii) provides reasonable cooperation at Freelancer''s expense.\n\n15.2 Exclusions from Freelancer Indemnity. Freelancer''s indemnity obligations under Section 15.1(b) do not apply to claims arising from: (a) Client Materials; (b) Client''s modifications to Deliverables not made by Freelancer; (c) Client''s use of Deliverables in violation of this Agreement or applicable law; or (d) Client''s combination of Deliverables with materials not provided by Freelancer, if the claim would not have arisen but for such combination.\n\n15.3 Indemnification by Client. Client shall indemnify, defend, and hold harmless Freelancer and its officers, employees, agents, successors, and assigns from and against any and all third-party claims, demands, losses, damages, liabilities, costs, and expenses (including reasonable attorneys'' fees and court costs) arising out of or relating to:\n  (a) Client''s breach of any representation, warranty, or obligation under this Agreement;\n  (b) Client Materials or Client''s instructions;\n  (c) Client''s use of the Deliverables in violation of applicable law or third-party rights;\n  (d) Client''s gross negligence or willful misconduct.\n\n15.4 Settlement. Neither Party may settle any claim requiring an admission of liability by the other Party or imposing non-monetary obligations on the other Party without such other Party''s prior written consent, which shall not be unreasonably withheld.","type":"negotiable","order":15},{"id":"limitation_liability","title":"16. LIMITATION OF LIABILITY","content":"16.1 Exclusion of Consequential Damages. TO THE MAXIMUM EXTENT PERMITTED BY LAW, IN NO EVENT SHALL EITHER PARTY BE LIABLE TO THE OTHER PARTY FOR ANY INDIRECT, INCIDENTAL, CONSEQUENTIAL, SPECIAL, EXEMPLARY, OR PUNITIVE DAMAGES, OR FOR ANY LOSS OF PROFITS, REVENUE, DATA, BUSINESS, GOODWILL, OR ANTICIPATED SAVINGS, ARISING OUT OF OR RELATED TO THIS AGREEMENT, WHETHER IN CONTRACT, TORT (INCLUDING NEGLIGENCE), STRICT LIABILITY, OR OTHERWISE, EVEN IF SUCH PARTY HAS BEEN ADVISED OF THE POSSIBILITY OF SUCH DAMAGES.\n\n16.2 Cap on Liability. TO THE MAXIMUM EXTENT PERMITTED BY LAW, EACH PARTY''S TOTAL AGGREGATE LIABILITY ARISING OUT OF OR RELATED TO THIS AGREEMENT SHALL NOT EXCEED THE GREATER OF: (A) THE TOTAL AMOUNTS PAID OR PAYABLE BY CLIENT TO FREELANCER UNDER THIS AGREEMENT IN THE TWELVE (12) MONTHS PRECEDING THE CLAIM; OR (B) {{payment_amount}}.\n\n16.3 Exceptions. The limitations in this Section 16 shall not apply to: (a) either Party''s breach of Section 10 (Confidentiality); (b) either Party''s indemnification obligations under Section 15; (c) either Party''s gross negligence or willful misconduct; (d) Freelancer''s infringement of Client''s intellectual property rights; or (e) amounts that cannot be limited under applicable law.\n\n16.4 Essential Element. THE PARTIES AGREE THAT THE LIMITATIONS OF LIABILITY IN THIS SECTION 16 ARE AN ESSENTIAL ELEMENT OF THIS AGREEMENT, THAT THEY ALLOCATE RISKS BETWEEN THE PARTIES, AND THAT THE AGREEMENT WOULD NOT HAVE BEEN ENTERED INTO WITHOUT SUCH LIMITATIONS.","type":"negotiable","order":16},{"id":"mechanic_lien_waiver","title":"17. MECHANIC''S LIEN WAIVER (IF APPLICABLE)","content":"17.1 Applicability. This Section 17 applies only if the Services involve improvements to real property located in Texas.\n\n17.2 Texas Property Code Compliance. The Parties acknowledge that Texas Property Code Chapter 53 governs mechanic''s and materialman''s liens on real property improvements.\n\n17.3 Conditional Lien Waiver. Upon receipt of each progress payment, Freelancer shall provide Client with a conditional waiver and release of lien in the form prescribed by Texas Property Code Section 53.284, to the extent of the payment received.\n\n17.4 Unconditional Lien Waiver. Upon receipt of final payment in full, Freelancer shall provide Client with an unconditional waiver and release of lien in the form prescribed by Texas Property Code Section 53.284.\n\n17.5 No Waiver of Lien Rights Before Payment. Nothing in this Agreement shall be construed as a waiver of Freelancer''s lien rights under Texas Property Code Chapter 53 prior to receipt of payment.\n\n17.6 Notices Required by Law. If the Services involve work on real property, Freelancer shall comply with all notice requirements under Texas Property Code Chapter 53, including any required preliminary or monthly notices.","type":"optional","order":17},{"id":"term_termination","title":"18. TERM; TERMINATION; CANCELLATION","content":"18.1 Term. This Agreement commences on the Effective Date and continues until: (a) all Services have been completed and all Deliverables have been accepted; (b) {{expiration_date}}; or (c) earlier termination under this Section 18, whichever occurs first.\n\n18.2 Termination for Convenience. Either Party may terminate this Agreement for convenience by providing written notice to the other Party at least {{notice_period}} days prior to the effective termination date (or 14 days if not specified).\n\n18.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party:\n  (a) Materially breaches this Agreement and fails to cure such breach within fifteen (15) days after receiving written notice specifying the breach (or such longer period as may be reasonably required to cure, not to exceed 30 days);\n  (b) Becomes insolvent, makes an assignment for the benefit of creditors, or files for bankruptcy;\n  (c) Engages in fraud or willful misconduct.\n\n18.4 Effect of Termination. Upon termination:\n  (a) Client shall pay Freelancer for all Services performed through the effective termination date, all approved expenses incurred prior to termination, and any non-cancellable commitments reasonably made by Freelancer;\n  (b) Freelancer shall deliver to Client all completed and in-progress Work Product and Deliverables (subject to payment);\n  (c) Each Party shall return or destroy the other Party''s Confidential Information as provided in Section 10.\n\n18.5 Cancellation Fee. If Client cancels the project after work has begun (other than for Freelancer''s material breach), Client acknowledges that Freelancer has reserved capacity and incurred opportunity costs. Accordingly, amounts paid are nonrefundable for Services performed, and Client shall pay for work completed plus {{cancellation_fee_percentage}}% of the remaining unpaid contract value (or 25% if not specified) as a cancellation fee.\n\n18.6 Survival. Sections 9 (Intellectual Property), 10 (Confidentiality), 11 (Non-Solicitation), 13 (DTPA), 15 (Indemnification), 16 (Limitation of Liability), and 20 (General Provisions) shall survive termination or expiration of this Agreement.","type":"standard","order":18},{"id":"governing_law_venue_texas","title":"19. GOVERNING LAW; VENUE; DISPUTE RESOLUTION","content":"19.1 Governing Law. This Agreement and any dispute arising out of or relating to this Agreement shall be governed by and construed in accordance with the laws of the State of Texas, without regard to its choice of law or conflict of laws principles.\n\n19.2 Venue. Subject to Section 19.3, the Parties hereby irrevocably consent to the exclusive jurisdiction and venue of the state and federal courts located in {{venue_county}} County, Texas, for any action or proceeding arising out of or relating to this Agreement. Each Party waives any objection to such jurisdiction and venue based on inconvenient forum or otherwise.\n\n19.3 Mandatory Pre-Suit Mediation. Before commencing any lawsuit or legal proceeding arising out of or relating to this Agreement, the Parties shall first attempt to resolve the dispute through good-faith mediation administered by a mutually agreed mediator or, if the Parties cannot agree, by the American Arbitration Association under its Commercial Mediation Procedures. Each Party shall bear its own costs for mediation, and the mediator''s fees shall be split equally.\n\n19.4 Attorneys'' Fees. In any action or proceeding to enforce or interpret this Agreement, the prevailing Party shall be entitled to recover its reasonable attorneys'' fees and costs from the non-prevailing Party, to the extent permitted by Texas law.\n\n19.5 Equitable Relief. Notwithstanding the foregoing, either Party may seek injunctive or other equitable relief in any court of competent jurisdiction to prevent actual or threatened misuse of Confidential Information or infringement of intellectual property rights, without the requirement of posting bond.\n\n19.6 Jury Trial Waiver. TO THE FULLEST EXTENT PERMITTED BY LAW, EACH PARTY HEREBY IRREVOCABLY WAIVES ANY RIGHT TO A JURY TRIAL IN ANY ACTION OR PROCEEDING ARISING OUT OF OR RELATING TO THIS AGREEMENT.","type":"standard","order":19},{"id":"general_provisions","title":"20. GENERAL PROVISIONS","content":"20.1 Entire Agreement. This Agreement, together with any written change orders, statements of work, or exhibits incorporated by reference, constitutes the entire agreement between the Parties regarding its subject matter and supersedes all prior or contemporaneous understandings, communications, and agreements, whether oral or written.\n\n20.2 Amendments. Any amendment or modification to this Agreement must be in writing and signed by both Parties.\n\n20.3 Assignment. Neither Party may assign or transfer this Agreement or any rights or obligations hereunder without the prior written consent of the other Party, except that either Party may assign this Agreement in connection with a merger, acquisition, or sale of substantially all of its assets, provided that the assignee agrees in writing to be bound by this Agreement. Any purported assignment in violation of this Section is void.\n\n20.4 Severability. If any provision of this Agreement is held invalid, illegal, or unenforceable by a court of competent jurisdiction, such provision shall be modified to the minimum extent necessary to make it valid and enforceable, or if modification is not possible, shall be severed, and the remaining provisions shall remain in full force and effect.\n\n20.5 Waiver. No waiver of any breach of this Agreement shall be deemed a waiver of any prior or subsequent breach. No waiver shall be effective unless in writing and signed by the waiving Party.\n\n20.6 Force Majeure. Neither Party shall be liable for delays or failures to perform caused by Force Majeure Events, provided that the affected Party: (a) gives prompt notice to the other Party; (b) uses commercially reasonable efforts to mitigate the impact and resume performance; and (c) resumes performance as soon as reasonably practicable.\n\n20.7 Notices. All notices required or permitted under this Agreement shall be in writing and shall be deemed delivered when: (a) delivered personally; (b) sent by overnight courier with tracking (upon confirmed delivery); (c) sent by certified or registered mail, return receipt requested (upon receipt); or (d) sent by email with confirmation of receipt (excluding automatic replies). Notices shall be sent to the addresses set forth in Section 21 or to such other address as a Party may designate by notice.\n\n20.8 Counterparts; Electronic Signatures. This Agreement may be executed in counterparts, each of which shall be deemed an original and all of which together shall constitute one instrument. Signatures transmitted electronically (including by email, DocuSign, or other e-signature platform) shall be deemed original signatures and shall be valid and binding, pursuant to Texas Business and Commerce Code Chapter 322 (Uniform Electronic Transactions Act).\n\n20.9 Headings. Section headings are for convenience only and shall not affect the interpretation of this Agreement.\n\n20.10 Construction. This Agreement shall be construed without regard to any presumption against the Party that drafted it. The word \"including\" means \"including without limitation.\" References to \"days\" mean calendar days unless otherwise specified.\n\n20.11 Relationship of Parties. Nothing in this Agreement creates a partnership, joint venture, agency, or employment relationship. Neither Party has the authority to bind the other or incur obligations on the other''s behalf.\n\n20.12 Third-Party Beneficiaries. This Agreement is for the sole benefit of the Parties and their permitted successors and assigns. Nothing herein confers any rights on any third party.\n\n20.13 Publicity. Neither Party shall issue any press release or public statement regarding this Agreement without the prior written consent of the other Party, except as required by law.","type":"standard","order":20},{"id":"notices_addresses","title":"21. NOTICE ADDRESSES","content":"21.1 Notices to Client:\nName/Title: {{party_a_name}}, {{party_a_title}}\nCompany: {{party_a_company}}\nAddress: {{party_a_address}}\nEmail: {{party_a_email}}\n\n21.2 Notices to Freelancer:\nName: {{party_b_name}}\nDBA: {{party_b_company}}\nAddress: {{party_b_address}}\nEmail: {{party_b_email}}","type":"standard","order":21}]'::jsonb,
